(function(){"use strict";var data=window.WG_DATA;var grids=data&&data.grids;if(!grids||typeof grids!=="object"){window.WGP_CATALOG=[];return}var seen={};var flat=[];Object.keys(grids).forEach(function(section){var arr=grids[section];if(!arr||!arr.length)return;arr.forEach(function(g){if(!g||!g.name)return;if(seen[g.name])return;seen[g.name]=true;flat.push({name:g.name,url:g.url||"",image:g.image||g.img||g.bg||"",by:g.by||"",preview:g.preview||"",pip:g.pip||null,section,cats:g.cats||null})})});window.WGP_CATALOG=flat})();
